// GSC date x query (ALL pages) -> fact_seo_query_daily rows.
const items = $input.all();
let rows = [];
for (const it of items) { rows = rows.concat((it.json && it.json.rows) || []); }
const out = [];
let issues = 0;
for (const r of rows) {
  const keys = r.keys || [];
  const date = String(keys[0] || '');
  const query = String(keys[1] || '');
  if (date.length !== 10 || !query) { issues++; continue; }
  out.push({
    activity_date: date,
    query: query,
    clicks: Number(r.clicks) || 0,
    impressions: Number(r.impressions) || 0,
    ctr: Number(r.ctr) || 0,
    avg_position: Number((Number(r.position) || 0).toFixed(2)),
    source: 'gsc'
  });
}
if (out.length === 0) {
  throw new Error('GSC query feed returned 0 usable rows - check site URL format and webmasters.readonly access');
}
const meta = { rows_in: rows.length, issues: issues, pages: items.length };
return out.map((json) => ({ json: Object.assign({}, json, { _meta: meta }) }));
